DECLARE
 vcontemRegistro Integer;
 vExisteColuna   INTEGER; 
BEGIN

  -- CODIGODASITUACAOTRIBUTARIA ? CODSITUACAOTRIBUTACAO
  SELECT COUNT(*)
    INTO vExisteColuna
    FROM USER_TAB_COLUMNS
   WHERE TABLE_NAME = 'PCCSTTRIBUTACAOIBSCBS'
     AND COLUMN_NAME = 'CODIGODASITUACAOTRIBUTARIA';

  IF vExisteColuna > 0 THEN
     EXECUTE IMMEDIATE 'ALTER TABLE PCCSTTRIBUTACAOIBSCBS RENAME COLUMN CODIGODASITUACAOTRIBUTARIA TO CODSITUACAOTRIBUTARIA';
  END IF;

  -- DESCRICAODASITUACAOTRIBUTARIA ? DESSITUACAOTRIBUTARIA
  SELECT COUNT(*)
    INTO vExisteColuna
    FROM USER_TAB_COLUMNS
   WHERE TABLE_NAME = 'PCCSTTRIBUTACAOIBSCBS'
     AND COLUMN_NAME = 'DESCRICAODASITUACAOTRIBUTARIA';

  IF vExisteColuna > 0 THEN
     EXECUTE IMMEDIATE 'ALTER TABLE PCCSTTRIBUTACAOIBSCBS RENAME COLUMN DESCRICAODASITUACAOTRIBUTARIA TO DESSITUACAOTRIBUTARIA';
  END IF;

  -- CODIGOCLASSIFICACAOTRIBUTARIA ? CODCLASSIFICACAOTRIBUTARIA
  SELECT COUNT(*)
    INTO vExisteColuna
    FROM USER_TAB_COLUMNS
   WHERE TABLE_NAME = 'PCCSTTRIBUTACAOIBSCBS'
     AND COLUMN_NAME = 'CODIGOCLASSIFICACAOTRIBUTARIA';

  IF vExisteColuna > 0 THEN
     EXECUTE IMMEDIATE 'ALTER TABLE PCCSTTRIBUTACAOIBSCBS RENAME COLUMN CODIGOCLASSIFICACAOTRIBUTARIA TO CODCLASSIFICACAOTRIBUTARIA';
  END IF;

  -- DESCCLASSIFICACACAOTRIBUTARIA ? DESCLASSIFICACAOTRIBUTARIA
  SELECT COUNT(*)
    INTO vExisteColuna
    FROM USER_TAB_COLUMNS
   WHERE TABLE_NAME = 'PCCSTTRIBUTACAOIBSCBS'
     AND COLUMN_NAME = 'DESCCLASSIFICACACAOTRIBUTARIA';

  IF vExisteColuna > 0 THEN
     EXECUTE IMMEDIATE 'ALTER TABLE PCCSTTRIBUTACAOIBSCBS RENAME COLUMN DESCCLASSIFICACACAOTRIBUTARIA TO DESCLASSIFICACAOTRIBUTARIA';
  END IF;

  
  SELECT COUNT(1) 
    INTO vcontemRegistro 
   FROM PCCSTTRIBUTACAOIBSCBS;
         
  IF  (vcontemRegistro > 0) THEN
    UPDATE PCCSTTRIBUTACAOIBSCBS T
       SET TRIBUTACAOGIBSCBS = 'Não'
     WHERE CODSITUACAOTRIBUTARIA IN (400, 410, 620, 800, 810, 811, 820);
   
    UPDATE PCCSTTRIBUTACAOIBSCBS
       SET TRIBUTACAOGIBSCBS = 'Sim'
     WHERE CODSITUACAOTRIBUTARIA NOT IN (400, 410, 620, 800, 810, 811, 820);   
 
     COMMIT;
  END IF;  
  
  IF (vcontemRegistro = 0) THEN
            EXECUTE IMMEDIATE q'[
